1	\chapter{Line bundles on schemes and the Picard group}
2	\label{chap:Picard_LineBundle}
3	
4	This chapter sets up the foundational Phase~B/C infrastructure: the type of \emph{line bundles} (invertible quasi-coherent sheaves) on a scheme $X$, the abelian-group structure under tensor product, and the pull-back functoriality. It is the smallest self-contained step toward the Picard scheme construction (Theorem~\ref{thm:Pic_representable}) and feeds the Jacobian gap chain.
5	
6	The chapter introduces no protected declarations: every definition and lemma here is auxiliary, supporting the construction of $\Pic_{C/k}$ in later phases.
7	
8	\section{Definition}
9	
10	\begin{definition}\leanok
11	[Line bundle on a scheme]
12	  \label{def:Scheme_LineBundle}
13	  \lean{AlgebraicGeometry.Scheme.LineBundle}
14	  Let $X$ be a scheme. A \emph{line bundle} on $X$ is an invertible quasi-coherent $\mathcal O_X$-module: a sheaf $L$ of $\mathcal O_X$-modules that is quasi-coherent and locally free of rank $1$. Equivalently: an object of the category of $\mathcal O_X$-modules that is invertible with respect to the tensor product $- \otimes_{\mathcal O_X} -$ in the symmetric monoidal category of $\mathcal O_X$-modules.
15	\end{definition}
16	
17	\begin{remark}
18	  Mathlib has the category of $\mathcal O_X$-modules and the quasi-coherence typeclass. The combination ``invertible quasi-coherent sheaf'' is not pre-packaged; it is the content of this definition.
19	\end{remark}
20	
21	\section{Group structure under tensor product}
22	
23	\begin{theorem}\leanok
24	[Picard group of a scheme]
25	  \label{thm:Scheme_Pic_commGroup}
26	  \lean{AlgebraicGeometry.Scheme.instCommGroupLineBundle}
27	  For every scheme $X$, the type of line bundles on $X$ (modulo isomorphism) carries a canonical commutative-group structure. The operation is tensor product over $\mathcal O_X$, the unit is the structure sheaf $\mathcal O_X$ itself, and the inverse of a line bundle $L$ is its $\mathcal O_X$-dual $L^\vee = \mathcal{H}om_{\mathcal O_X}(L, \mathcal O_X)$.
28	
29	  We denote this group by $\Pic(X)$ and call it the \emph{Picard group} of $X$.
30	\end{theorem}
31	
32	\begin{proof}
33	  \uses{def:Scheme_LineBundle}
34	  \leanok
35	  Tensor product of two invertible quasi-coherent sheaves is invertible quasi-coherent (locally on $X$ this reduces to the corresponding statement for invertible modules over commutative rings, which Mathlib has). The structure sheaf is the tensor unit. The dual sheaf is the inverse: $L \otimes_{\mathcal O_X} L^\vee \cong \mathcal O_X$ canonically. Commutativity and associativity descend from the symmetric monoidal structure on the category of $\mathcal O_X$-modules.
36	\end{proof}
37	
38	\section{Pull-back functoriality}
39	
40	\begin{theorem}\leanok
41	[Pull-back of line bundles]
42	  \label{thm:Scheme_Pic_pullback}
43	  \lean{AlgebraicGeometry.Scheme.Pic.pullback}
44	  Let $f \colon X \to Y$ be a morphism of schemes. Pull-back of $\mathcal O_Y$-modules along $f$ restricts to a group homomorphism
45	  \[
46	    f^* \colon \Pic(Y) \;\to\; \Pic(X),\qquad L \;\mapsto\; f^* L \;:=\; f^{-1} L \otimes_{f^{-1}\mathcal O_Y} \mathcal O_X.
47	  \]
48	  Pull-back preserves invertibility, commutes with tensor product, and is functorial: $(\mathrm{id}_X)^* = \mathrm{id}_{\Pic(X)}$ and $(f \circ g)^* = g^* \circ f^*$.
49	\end{theorem}
50	
51	\begin{proof}
52	  \uses{thm:Scheme_Pic_commGroup}
53	  \leanok
54	  Mathlib has the tensor product of $\mathcal O_X$-modules and the pullback of sheaves of modules along a scheme morphism. Pull-back commutes with tensor product. Functoriality is the standard sheaf-pullback functoriality.
55	\end{proof}
56	
57	\section{Use in the project}
58	
59	The Picard group $\Pic(X)$ is the underlying \emph{set} (modulo isomorphism) of the Picard \emph{scheme} $\Pic_{C/k}$ in the curve case; the scheme structure adds a $k$-scheme of finite type representing the relative Picard functor $S \mapsto \Pic(C \times_k S) / \Pic(S)$.
60	
61	This chapter is therefore the gateway to:
62	\begin{itemize}
63	  \item Definition~\ref{def:Pic_functor} (Picard functor of $C/k$) --- quotient by $\Pic(S)$ uses Theorem~\ref{thm:Scheme_Pic_pullback}.
64	  \item Theorem~\ref{thm:Pic_representable} (representability of the Picard scheme) --- uses the full $\Pic$ machinery built here.
65	  \item Definition~\ref{def:ofCurve} (Abel--Jacobi map) --- defined via the line bundle $\mathcal O_{C \times C}(\Delta - p_1^* P)$ on $C \times C$, an explicit element of $\Pic(C \times C)$.
66	\end{itemize}
67	
68	\section{Mathlib gap}
69	
70	Mathlib has:
71	\begin{itemize}
72	  \item The abelian category of sheaves of $\mathcal O_X$-modules on a scheme $X$.
73	  \item Quasi-coherence as data on a sheaf of modules.
74	  \item Invertibility for modules over a commutative ring.
75	  \item The Picard group of a commutative ring.
76	\end{itemize}
77	
78	What is missing and supplied by this chapter:
79	\begin{itemize}
80	  \item A scheme-side type of \emph{invertible quasi-coherent} sheaves and the proof that this property is preserved by tensor product.
81	  \item A scheme-side commutative-group instance on the Picard group.
82	  \item A scheme-morphism-functorial pull-back homomorphism $\Pic(Y) \to \Pic(X)$.
83	\end{itemize}
84	
85	These are mapped to Phase~B/C step~1 of the project strategy.
86

